package bio.problems

import bio.algorithms.protein.InferMRna
import bio.domain.protein.ProteinString
import cats.effect.IO

object MRNAProb {

  def solve(): IO[Unit] = {

    val sample = ""
    val proteinString = ProteinString.unsafeFrom(sample)

    val result = InferMRna.count(proteinString)
    IO.println(s"${result}")
  }

}
